import json

def generate_moves(start_on_main, current_move_index, target_move_index, is_first_turn):
    moves = []
    if start_on_main:
        moves.append('A')
        moves.append('sleep 1000')

    if is_first_turn:
        current_move_index = 1

    diff = target_move_index - current_move_index
    if diff > 0:
        if diff == 3:
            moves.append('Up')
            moves.append('sleep 300')
        else:
            for _ in range(diff):
                moves.append('Down')
                moves.append('sleep 300')
    elif diff < 0:
        if diff == -3:
            moves.append('Down')
            moves.append('sleep 300')
        else:
            for _ in range(abs(diff)):
                moves.append('Up')
                moves.append('sleep 300')

    moves.append('A')
    moves.append('sleep 1000')
    return moves

print(json.dumps(generate_moves(
    input_data.get('start_on_main', True),
    int(input_data.get('current_move_index', 1)),
    int(input_data.get('target_move_index', 1)),
    input_data.get('is_first_turn', False)
)))

