import json
import sys

def generate_sequence(input_data):
    # From main battle menu, RUN is Right, Down, A
    sequence = ['Right', 'Down', 'sleep 300', 'A']
    return json.dumps(sequence)

if __name__ == '__main__':
    input_data = json.loads(sys.argv[1])
    print(generate_sequence(input_data))
